const express = require('express');
const app = express();
const bodyParser = require('body-parser');

app.use(bodyParser.json());

// Endpoint for completing levels
app.post('/levels', (req, res) => {
  const levelData = req.body;
  // Save the level data to a database or file
  res.status(201).send('Level completed!');
});

// Endpoint for claiming rewards
app.post('/rewards', (req, res) => {
  const rewardData = req.body;
  // Check if the client-reported metrics meet the requirements for claiming a reward
  if (rewardData.score >= 10 && rewardData.time <= 30) {
    res.status(200).send('Reward claimed!');
  } else {
    res.status(400).send('Insufficient metrics to claim reward.');
  }
});

app.listen(3000, () => {
  console.log('Server started on port 3000');
});